transform_js:
const axisData = []; const centerData = []; const lowerData = []; const upperData = [];
rawData.rows.forEach(r => {
  axisData.push(r.time);
  centerData.push(r.value);
  // EChartsで帯を描くには、下限値を透明な線のベースとし、その上に (上限 - 下限) 分の面積を積層面グラフとして重ねる技法を使います。
  lowerData.push(r.lower);
  upperData.push(r.upper - r.lower);
});
transformedData = { axisData, centerData, lowerData, upperData };

echarts_js:
option = {
  title: {
    text: 'Sales Forecast (Confidence Band)',
    left: 'center'
  },
  tooltip: {
    trigger: 'axis',
    formatter: function(params) {
       const time = params[0].name;
       const center = params.find(p => p.seriesName === 'Average').value;
       const lower = params.find(p => p.seriesName === 'Lower Bound').value;
       const band = params.find(p => p.seriesName === 'Confidence Band').value;
       const upper = lower + band;
       return `<b>${time}</b><br/>Average: ${center}<br/>Range: ${lower} - ${upper}`;
    }
  },
  grid: { left: '3%', right: '4%', bottom: '3%', containLabel: true },
  xAxis: {
    type: 'category',
    boundaryGap: false,
    data: transformedData.axisData
  },
  yAxis: {
    type: 'value',
    scale: true
  },
  series: [
    {
      name: 'Lower Bound',
      type: 'line',
      data: transformedData.lowerData,
      lineStyle: { opacity: 0 },
      stack: 'confidence-band',
      symbol: 'none'
    },
    {
      name: 'Confidence Band',
      type: 'line',
      data: transformedData.upperData,
      lineStyle: { opacity: 0 },
      areaStyle: { color: '#ccc' },
      stack: 'confidence-band',
      symbol: 'none'
    },
    {
      name: 'Average',
      type: 'line',
      data: transformedData.centerData,
      itemStyle: { color: '#d33' },
      lineStyle: { width: 3 },
      symbol: 'circle',
      symbolSize: 8
    }
  ]
};
